3	// aes_key_mem.v
4	// -------------
5	// The AES key memory including round key generator.
6	//
7	//======================================================================
8	
9	module aes_key_mem(
10	                   input wire            clk,
11	                   input wire            reset_n,
12	
13	                   input wire [255 : 0]  key,
14	                   input wire            keylen,
15	                   input wire            init,
16	
17	                   input wire    [3 : 0] round,
18	                   output wire [127 : 0] round_key,
19	                   output wire           ready,
20	
21	
22	                   output wire [31 : 0]  sboxw,
23	                   input wire  [31 : 0]  new_sboxw
24	                  );
25	
26	
27	  //----------------------------------------------------------------
28	  // Parameters.
29	  //----------------------------------------------------------------
30	  localparam AES_128_BIT_KEY = 1'h0;
31	  localparam AES_256_BIT_KEY = 1'h1;
32	
33	  localparam AES_128_NUM_ROUNDS = 10;
34	  localparam AES_256_NUM_ROUNDS = 14;
35	
36	  localparam CTRL_IDLE     = 3'h0;
37	  localparam CTRL_INIT     = 3'h1;
38	  localparam CTRL_GENERATE = 3'h2;
39	  localparam CTRL_DONE     = 3'h3;
40	
41	
42	  //----------------------------------------------------------------
43	  // Registers.
44	  //----------------------------------------------------------------
45	  reg [127 : 0] key_mem [0 : 14];
46	  reg [127 : 0] key_mem_new;
47	  reg           key_mem_we;
48	
49	  reg [127 : 0] prev_key0_reg;
50	  reg [127 : 0] prev_key0_new;
51	  reg           prev_key0_we;
52	
53	  reg [127 : 0] prev_key1_reg;
54	  reg [127 : 0] prev_key1_new;
55	  reg           prev_key1_we;
56	
57	  reg [3 : 0] round_ctr_reg;
58	  reg [3 : 0] round_ctr_new;
59	  reg         round_ctr_rst;
60	  reg         round_ctr_inc;
61	  reg         round_ctr_we;
62	
63	  reg [2 : 0] key_mem_ctrl_reg;
64	  reg [2 : 0] key_mem_ctrl_new;
65	  reg         key_mem_ctrl_we;
66	
67	  reg         ready_reg;
68	  reg         ready_new;
69	  reg         ready_we;
70	
71	  reg [7 : 0] rcon_reg;
72	  reg [7 : 0] rcon_new;
73	  reg         rcon_we;
74	  reg         rcon_set;
75	  reg         rcon_next;
76	
77	
78	  //----------------------------------------------------------------
79	  // Wires.
80	  //----------------------------------------------------------------
81	  reg [31 : 0]  tmp_sboxw;
82	  reg           round_key_update;
83	  reg [127 : 0] tmp_round_key;
84	
85	
86	  //----------------------------------------------------------------
87	  // Concurrent assignments for ports.
88	  //----------------------------------------------------------------
89	  assign round_key = tmp_round_key;
90	  assign ready     = ready_reg;
91	  assign sboxw     = tmp_sboxw;
92	
93	
94	  //----------------------------------------------------------------
95	  // reg_update
96	  //
97	  // Update functionality for all registers in the core.
98	  // All registers are positive edge triggered with asynchronous
99	  // active low reset. All registers have write enable.
100	  //----------------------------------------------------------------
101	  always @ (posedge clk or negedge reset_n)
102	    begin: reg_update
103	      integer i;
104	
105	      if (!reset_n)
106	        begin
107	          for (i = 0 ; i <= AES_256_NUM_ROUNDS ; i = i + 1)
108	            key_mem [i] <= 128'h0;
109	
110	          ready_reg        <= 1'b0;
111	          rcon_reg         <= 8'h0;
112	          round_ctr_reg    <= 4'h0;
113	          prev_key0_reg    <= 128'h0;
114	          prev_key1_reg    <= 128'h0;
115	          key_mem_ctrl_reg <= CTRL_IDLE;
116	        end
117	      else
118	        begin
119	          if (ready_we)
120	            ready_reg <= ready_new;
121	
122	          if (rcon_we)
123	            rcon_reg <= rcon_new;
124	
125	          if (round_ctr_we)
126	            round_ctr_reg <= round_ctr_new;
127	
128	          if (key_mem_we)
129	            key_mem[round_ctr_reg] <= key_mem_new;
130	
131	          if (prev_key0_we)
132	            prev_key0_reg <= prev_key0_new;
133	
134	          if (prev_key1_we)
135	            prev_key1_reg <= prev_key1_new;
136	
137	          if (key_mem_ctrl_we)
138	            key_mem_ctrl_reg <= key_mem_ctrl_new;
139	        end
140	    end // reg_update
141	
142	
143	  //----------------------------------------------------------------
144	  // key_mem_read
145	  //
146	  // Combinational read port for the key memory.
147	  //----------------------------------------------------------------
148	  always @*
149	    begin : key_mem_read
150	      tmp_round_key = key_mem[round];
151	    end // key_mem_read
152	
153	
154	  //----------------------------------------------------------------
155	  // round_key_gen
156	  //
157	  // The round key generator logic for AES-128 and AES-256.
158	  //----------------------------------------------------------------
159	  always @*
160	    begin: round_key_gen
161	      reg [31 : 0] w0, w1, w2, w3, w4, w5, w6, w7;
162	      reg [31 : 0] k0, k1, k2, k3;
163	      reg [31 : 0] rconw, rotstw, tw, trw;
164	
165	      // Default assignments.
166	      key_mem_new   = 128'h0;
167	      key_mem_we    = 1'b0;
168	      prev_key0_new = 128'h0;
169	      prev_key0_we  = 1'b0;
170	      prev_key1_new = 128'h0;
171	      prev_key1_we  = 1'b0;
172	
173	      k0 = 32'h0;
174	      k1 = 32'h0;
175	      k2 = 32'h0;
176	      k3 = 32'h0;
177	
178	      rcon_set   = 1'b1;
179	      rcon_next  = 1'b0;
180	
181	      // Extract words and calculate intermediate values.
182	      // Perform rotation of sbox word etc.
183	      w0 = prev_key0_reg[127 : 096];
184	      w1 = prev_key0_reg[095 : 064];
185	      w2 = prev_key0_reg[063 : 032];
186	      w3 = prev_key0_reg[031 : 000];
187	
188	      w4 = prev_key1_reg[127 : 096];
189	      w5 = prev_key1_reg[095 : 064];
190	      w6 = prev_key1_reg[063 : 032];
191	      w7 = prev_key1_reg[031 : 000];
192	
193	      rconw = {rcon_reg, 24'h0};
194	      tmp_sboxw = w7;
195	      rotstw = {new_sboxw[23 : 00], new_sboxw[31 : 24]};
196	      trw = rotstw ^ rconw;
197	      tw = new_sboxw;
198	
199	      // Generate the specific round keys.
200	      if (round_key_update)
201	        begin
202	          rcon_set   = 1'b0;
203	          key_mem_we = 1'b1;
204	          case (keylen)
205	            AES_128_BIT_KEY:
206	              begin
207	                if (round_ctr_reg == 0)
208	                  begin
209	                    key_mem_new   = key[255 : 128];
210	                    prev_key1_new = key[255 : 128];
211	                    prev_key1_we  = 1'b1;
212	                    rcon_next     = 1'b1;
213	                  end
214	                else
215	                  begin
216	                    k0 = w4 ^ trw;
217	                    k1 = w5 ^ w4 ^ trw;
218	                    k2 = w6 ^ w5 ^ w4 ^ trw;
219	                    k3 = w7 ^ w6 ^ w5 ^ w4 ^ trw;
220	
221	                    key_mem_new   = {k0, k1, k2, k3};
222	                    prev_key1_new = {k0, k1, k2, k3};
223	                    prev_key1_we  = 1'b1;
224	                    rcon_next     = 1'b1;
225	                  end
226	              end
227	
228	            AES_256_BIT_KEY:
229	              begin
230	                if (round_ctr_reg == 0)
231	                  begin
232	                    key_mem_new   = key[255 : 128];
233	                    prev_key0_new = key[255 : 128];
234	                    prev_key0_we  = 1'b1;
235	                  end
236	                else if (round_ctr_reg == 1)
237	                  begin
238	                    key_mem_new   = key[127 : 0];
239	                    prev_key1_new = key[127 : 0];
240	                    prev_key1_we  = 1'b1;
241	                    rcon_next     = 1'b1;
242	                  end
243	                else
244	                  begin
245	                    if (round_ctr_reg[0] == 0)
246	                      begin
247	                        k0 = w0 ^ trw;
248	                        k1 = w1 ^ w0 ^ trw;
249	                        k2 = w2 ^ w1 ^ w0 ^ trw;
250	                        k3 = w3 ^ w2 ^ w1 ^ w0 ^ trw;
251	                      end
252	                    else
253	                      begin
254	                        k0 = w0 ^ tw;
255	                        k1 = w1 ^ w0 ^ tw;
256	                        k2 = w2 ^ w1 ^ w0 ^ tw;
257	                        k3 = w3 ^ w2 ^ w1 ^ w0 ^ tw;
258	                        rcon_next = 1'b1;
259	                      end
260	
261	                    // Store the generated round keys.
262	                    key_mem_new   = {k0, k1, k2, k3};
263	                    prev_key1_new = {k0, k1, k2, k3};
264	                    prev_key1_we  = 1'b1;
265	                    prev_key0_new = prev_key1_reg;
266	                    prev_key0_we  = 1'b1;
267	                  end
268	              end
269	
270	            default:
271	              begin
272	              end
273	          endcase // case (keylen)
274	        end
275	    end // round_key_gen
276	
277	
278	  //----------------------------------------------------------------
279	  // rcon_logic
280	  //
281	  // Caclulates the rcon value for the different key expansion
282	  // iterations.
283	  //----------------------------------------------------------------
284	  always @*
285	    begin : rcon_logic
286	      reg [7 : 0] tmp_rcon;
287	      rcon_new = 8'h00;
288	      rcon_we  = 1'b0;
289	
290	      tmp_rcon = {rcon_reg[6 : 0], 1'b0} ^ (8'h1b & {8{rcon_reg[7]}});
291	
292	      if (rcon_set)
293	        begin
294	          rcon_new = 8'h8d;
295	          rcon_we  = 1'b1;
296	        end
297	
298	      if (rcon_next)
299	        begin
300	          rcon_new = tmp_rcon[7 : 0];
301	          rcon_we  = 1'b1;
302	        end
303	    end
304	
305	
306	  //----------------------------------------------------------------
307	  // round_ctr
308	  //
309	  // The round counter logic with increase and reset.
310	  //----------------------------------------------------------------
311	  always @*
312	    begin : round_ctr
313	      round_ctr_new = 4'h0;
314	      round_ctr_we  = 1'b0;
315	
316	      if (round_ctr_rst)
317	        begin
318	          round_ctr_new = 4'h0;
319	          round_ctr_we  = 1'b1;
320	        end
321	
322	      else if (round_ctr_inc)
323	        begin
324	          round_ctr_new = round_ctr_reg + 1'b1;
325	          round_ctr_we  = 1'b1;
326	        end
327	    end
328	
329	
330	  //----------------------------------------------------------------
331	  // key_mem_ctrl
332	  //
333	  //
334	  // The FSM that controls the round key generation.
335	  //----------------------------------------------------------------
336	  always @*
337	    begin: key_mem_ctrl
338	      reg [3 : 0] num_rounds;
339	
340	      // Default assignments.
341	      ready_new        = 1'b0;
342	      ready_we         = 1'b0;
343	      round_key_update = 1'b0;
344	      round_ctr_rst    = 1'b0;
345	      round_ctr_inc    = 1'b0;
346	      key_mem_ctrl_new = CTRL_IDLE;
347	      key_mem_ctrl_we  = 1'b0;
348	
349	      if (keylen == AES_128_BIT_KEY)
350	        num_rounds = AES_128_NUM_ROUNDS;
351	      else
352	        num_rounds = AES_256_NUM_ROUNDS;
353	
354	      case(key_mem_ctrl_reg)
355	        CTRL_IDLE:
356	          begin
357	            if (init)
358	              begin
359	                ready_new        = 1'b0;
360	                ready_we         = 1'b1;
361	                key_mem_ctrl_new = CTRL_INIT;
362	                key_mem_ctrl_we  = 1'b1;
363	              end
364	          end
365	
366	        CTRL_INIT:
367	          begin
368	            round_ctr_rst    = 1'b1;
369	            key_mem_ctrl_new = CTRL_GENERATE;
370	            key_mem_ctrl_we  = 1'b1;
371	          end
372	
373	        CTRL_GENERATE:
374	          begin
375	            round_ctr_inc    = 1'b1;
376	            round_key_update = 1'b1;
377	            if (round_ctr_reg == num_rounds)
378	              begin
379	                key_mem_ctrl_new = CTRL_DONE;
380	                key_mem_ctrl_we  = 1'b1;
381	              end
382	          end
383	
384	        CTRL_DONE:
385	          begin
386	            ready_new        = 1'b1;
387	            ready_we         = 1'b1;
388	            key_mem_ctrl_new = CTRL_IDLE;
389	            key_mem_ctrl_we  = 1'b1;
390	          end
391	
392	        default:
393	          begin
394	          end
395	      endcase // case (key_mem_ctrl_reg)
396	
397	    end // key_mem_ctrl
398	endmodule // aes_key_mem
399	
